import { useState } from 'react';

const Projects = () => {
  const [activeFilter, setActiveFilter] = useState('All');
  
  const projects = [
    { id: 1, name: "Sunrise Heights", type: "Residential", status: "Ongoing", location: "Panchavati", price: "₹45 Lakhs", image: "https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?w=800" },
    { id: 2, name: "Green Valley Villas", type: "Residential", status: "Completed", location: "College Road", price: "₹1.2 Cr", image: "https://images.unsplash.com/photo-1560185127-6ed189bf02f4?w=800" },
    { id: 3, name: "Business Plaza", type: "Commercial", status: "Completed", location: "CBD", price: "₹1.5 Cr", image: "https://images.unsplash.com/photo-1497366216548-37526070297c?w=800" },
    { id: 4, name: "Industrial Warehouse", type: "Commercial", status: "Ongoing", location: "Ambad", price: "₹80 Lakhs", image: "https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?w=800" },
    { id: 5, name: "Riverdale Farmhouses", type: "Residential", status: "Upcoming", location: "Gangapur Road", price: "₹2.5 Cr", image: "https://images.unsplash.com/photo-1500076656116-558758c991c1?w=800" }
  ];
  
  const filters = ['All', 'Residential', 'Commercial', 'Ongoing', 'Completed', 'Upcoming'];
  
  const filteredProjects = () => {
    if (activeFilter === 'All') return projects;
    if (activeFilter === 'Residential') return projects.filter(p => p.type === 'Residential');
    if (activeFilter === 'Commercial') return projects.filter(p => p.type === 'Commercial');
    return projects.filter(p => p.status === activeFilter);
  };
  
  const getStatusColor = (status) => {
    switch(status) {
      case 'Ongoing': return 'bg-green-500';
      case 'Completed': return 'bg-blue-500';
      case 'Upcoming': return 'bg-orange-500';
      default: return 'bg-gray-500';
    }
  };

  return (
    <div className="pt-32 pb-16 bg-gray-50 min-h-screen">
      <div className="container-custom">
        <h1 className="text-4xl font-bold text-center mb-4">Our Projects</h1>
        <p className="text-center text-gray-600 mb-12">Discover premium properties in Nashik</p>
        
        <div className="flex flex-wrap justify-center gap-3 mb-12">
          {filters.map(filter => (
            <button
              key={filter}
              onClick={() => setActiveFilter(filter)}
              className={`px-5 py-2 rounded-lg font-medium transition ${
                activeFilter === filter ? 'bg-primary text-white shadow-lg' : 'bg-white text-gray-700 hover:bg-gray-100 border'
              }`}
            >
              {filter}
            </button>
          ))}
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredProjects().map(project => (
            <div key={project.id} className="bg-white rounded-xl shadow-lg overflow-hidden hover:shadow-2xl transition hover:-translate-y-2">
              <div className="relative h-56">
                <img src={project.image} alt={project.name} className="w-full h-full object-cover" />
                <div className="absolute top-4 right-4">
                  <span className={`${getStatusColor(project.status)} text-white px-3 py-1 rounded-full text-xs font-semibold`}>
                    {project.status}
                  </span>
                </div>
              </div>
              <div className="p-5">
                <h3 className="text-xl font-bold mb-2">{project.name}</h3>
                <p className="text-gray-500 text-sm mb-2">{project.type} • {project.location}</p>
                <p className="text-primary font-bold text-lg">{project.price}</p>
                <button className="w-full mt-4 bg-primary text-white py-2 rounded-lg hover:bg-opacity-90 transition font-medium">
                  View Details
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Projects;
